"use client";

import { useState } from "react";
import { Button, Input } from "@/components/ui";

interface CallToActionProps {
  headline: string;
  description: string;
  buttonText: string;
  helperText?: string;
}

export function CallToAction({
  headline,
  description,
  buttonText,
  helperText,
}: CallToActionProps) {
  const [email, setEmail] = useState("");
  const [isSubmitted, setIsSubmitted] = useState(false);

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (email.trim()) {
      // Placeholder for form submission
      console.log("Submitted:", email);
      setIsSubmitted(true);
    }
  };

  return (
    <section
      id="request-pickup"
      className="section-padding bg-background relative overflow-hidden"
    >
      {/* Background Gradients */}
      <div className="absolute inset-0 overflow-hidden pointer-events-none">
        <div
          className="absolute top-1/2 left-1/4 -translate-x-1/2 -translate-y-1/2 w-96 h-96 bg-muted rounded-full blur-3xl opacity-40 animate-pulse-soft"
          aria-hidden="true"
        />
        <div
          className="absolute top-1/2 right-1/4 translate-x-1/2 -translate-y-1/2 w-96 h-96 bg-accent rounded-full blur-3xl opacity-40 animate-pulse-soft"
          style={{ animationDelay: "2s" }}
          aria-hidden="true"
        />
      </div>

      <div className="relative z-10 max-w-lg mx-auto text-center">
        {/* Icon */}
        <div className="w-16 h-16 bg-foreground rounded-xl flex items-center justify-center mx-auto mb-8">
          <div className="w-3 h-3 bg-primary rounded-full" />
        </div>

        <h2 className="text-3xl sm:text-4xl font-semibold tracking-tight text-foreground mb-4">
          {headline}
        </h2>

        <p className="text-lg text-muted-foreground mb-8">{description}</p>

        {isSubmitted ? (
          <div className="bg-accent/50 rounded-xl p-6">
            <svg
              className="w-12 h-12 text-primary mx-auto mb-4"
              fill="none"
              stroke="currentColor"
              viewBox="0 0 24 24"
            >
              <path
                strokeLinecap="round"
                strokeLinejoin="round"
                strokeWidth={2}
                d="M5 13l4 4L19 7"
              />
            </svg>
            <p className="text-foreground font-medium">
              Thanks! We&apos;ll be in touch soon.
            </p>
          </div>
        ) : (
          <form onSubmit={handleSubmit} className="space-y-4">
            <Input
              type="email"
              placeholder="Enter your email"
              value={email}
              onChange={(e) => setEmail(e.target.value)}
              required
            />
            <Button type="submit" variant="dark" size="lg" className="w-full">
              {buttonText}
            </Button>
            {helperText && (
              <p className="text-sm text-muted-foreground">{helperText}</p>
            )}
          </form>
        )}
      </div>
    </section>
  );
}
